import { Link, useLocation } from 'react-router-dom';
import { Camera, Key, Activity } from 'lucide-react';
import { motion } from 'framer-motion';

export default function Header() {
  const location = useLocation();
  const isDarkArea = location.pathname === '/' || location.pathname === '/login' || location.pathname === '/register';

  const navColor = isDarkArea ? '#94A3B8' : '#64748B';
  const navActiveColor = isDarkArea ? 'white' : '#0F172A';
  const navActiveBg = isDarkArea ? 'rgba(255,255,255,0.1)' : '#F1F5F9';
  const headerBg = isDarkArea ? 'rgba(9, 13, 20, 0.7)' : 'rgba(255,255,255,0.85)';
  const borderColor = isDarkArea ? 'rgba(255,255,255,0.05)' : 'rgba(0,0,0,0.05)';
  const titleColor = isDarkArea ? 'white' : '#0F172A';

  const getStyle = (path) => ({
    color: location.pathname === path ? navActiveColor : navColor,
    display: 'flex', gap: '0.5rem', alignItems: 'center', 
    fontWeight: location.pathname === path ? '600' : '500',
    textDecoration: 'none', transition: 'all 0.3s ease',
    padding: '0.6rem 1.25rem',
    borderRadius: '99px',
    background: location.pathname === path ? navActiveBg : 'transparent'
  });

  return (
    <header 
      style={{ background: headerBg, backdropFilter: 'blur(24px)', WebkitBackdropFilter: 'blur(24px)', borderBottom: `1px solid ${borderColor}`, position: 'sticky', top: 0, zIndex: 100, padding: '1rem 0', fontFamily: '"Outfit", sans-serif', transition: 'all 0.3s' }}
    >
      <div style={{ maxWidth: '1280px', margin: '0 auto', display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '0 1.5rem' }}>

        <Link to="/" style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', textDecoration: 'none' }}>
          <div style={{ background: 'linear-gradient(135deg, #22C55E 0%, #16A34A 100%)', borderRadius: '12px', padding: '0.5rem', display: 'flex', boxShadow: '0 8px 16px rgba(34,197,94,0.25)' }}>
            <Activity size={24} color="white" />
          </div>
          <span style={{ fontSize: '1.4rem', fontWeight: 800, color: titleColor, letterSpacing: '-0.02em', transition: 'color 0.3s' }}>AgriScan</span>
        </Link>

        <nav style={{ display: 'flex', alignItems: 'center', gap: '0.25rem', background: isDarkArea ? 'rgba(255,255,255,0.02)' : 'white', border: `1px solid ${borderColor}`, padding: '0.35rem', borderRadius: '99px', boxShadow: isDarkArea ? 'none' : '0 4px 20px rgba(0,0,0,0.03)', transition: 'all 0.3s' }}>
           <Link to="/dashboard" style={getStyle('/dashboard')} onMouseOver={e=>e.currentTarget.style.color = navActiveColor} onMouseOut={e=>e.currentTarget.style.color = location.pathname === '/dashboard' ? navActiveColor : navColor}>Dashboard</Link>
           <Link to="/upload" style={{ ...getStyle('/upload'), color: location.pathname === '/upload' ? 'white' : (isDarkArea ? '#4ADE80' : '#22C55E'), background: location.pathname === '/upload' ? '#22C55E' : 'transparent', fontWeight: 600 }} onMouseOver={e=>{if(location.pathname!=='/upload') e.currentTarget.style.background=isDarkArea ? 'rgba(255,255,255,0.1)' : 'rgba(34,197,94,0.1)'}} onMouseOut={e=>{if(location.pathname!=='/upload') e.currentTarget.style.background='transparent'}}>
             <Camera size={18}/> Scan
           </Link>
           <Link to="/history" style={getStyle('/history')} onMouseOver={e=>e.currentTarget.style.color = navActiveColor} onMouseOut={e=>e.currentTarget.style.color = location.pathname === '/history' ? navActiveColor : navColor}>History</Link>
           <Link to="/profile" style={getStyle('/profile')} onMouseOver={e=>e.currentTarget.style.color = navActiveColor} onMouseOut={e=>e.currentTarget.style.color = location.pathname === '/profile' ? navActiveColor : navColor}>Profile</Link>
           <Link to="/admin" style={getStyle('/admin')} onMouseOver={e=>e.currentTarget.style.color = navActiveColor} onMouseOut={e=>e.currentTarget.style.color = location.pathname === '/admin' ? navActiveColor : navColor}><Key size={16} /> Admin</Link>
        </nav>

        <Link 
          to="/login" 
          style={{ background: isDarkArea ? 'white' : '#0F172A', color: isDarkArea ? '#0F172A' : 'white', padding: '0.75rem 1.75rem', borderRadius: '999px', fontWeight: 700, textDecoration: 'none', transition: 'all 0.3s cubic-bezier(0.16, 1, 0.3, 1)', boxShadow: isDarkArea ? '0 10px 20px rgba(255,255,255,0.1)' : '0 10px 20px rgba(15,23,42,0.15)' }}
          onMouseOver={e => {e.currentTarget.style.transform='translateY(-2px)'; e.currentTarget.style.boxShadow=isDarkArea ? '0 15px 25px rgba(255,255,255,0.2)' : '0 15px 25px rgba(15,23,42,0.2)';}}
          onMouseOut={e => {e.currentTarget.style.transform='translateY(0)'; e.currentTarget.style.boxShadow=isDarkArea ? '0 10px 20px rgba(255,255,255,0.1)' : '0 10px 20px rgba(15,23,42,0.15)';}}
        >
          Sign In
        </Link>
      </div>
      <style>{`
        @media(max-width: 900px) {
          nav { display: none !important; }
        }
      `}</style>
    </header>
  );
}

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Calendar, Search, ChevronRight, ShieldAlert, CheckCircle, Clock } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const MOCK_HISTORY = [
  { 
    id: 'REF-0892', 
    disease: 'Tomato Early Blight', 
    confidence: 0.98, 
    crop: 'Tomato Plant', 
    date: 'Today, 10:45 AM', 
    status: 'Diseased',
    img: '/src/assets/placeholder.jpg', // Replace with proper image path
    description: 'Early blight is a common disease of tomatoes caused by the fungus Alternaria linariae. It primarily affects leaves, stems, and fruit, causing target-like spots. Immediate treatment is recommended.'
  },
  { 
    id: 'REF-0891', 
    disease: 'Healthy Crop', 
    confidence: 0.99, 
    crop: 'Bell Pepper', 
    date: 'Yesterday, 04:20 PM', 
    status: 'Healthy',
    img: '/src/assets/placeholder.jpg',
    description: 'No diseases detected. The plant is displaying vibrant, strong leaves without deformations.'
  },
  { 
    id: 'REF-0884', 
    disease: 'Powdery Mildew', 
    confidence: 0.91, 
    crop: 'Zucchini', 
    date: 'Mar 15, 2026', 
    status: 'Diseased',
    img: '/src/assets/placeholder.jpg',
    description: 'Identified white powdery spots on leaves indicative of Powdery Mildew. Requires fungicide application.'
  },
  { 
    id: 'REF-0879', 
    disease: 'Septoria Leaf Spot', 
    confidence: 0.88, 
    crop: 'Tomato Plant', 
    date: 'Mar 10, 2026', 
    status: 'Diseased',
    img: '/src/assets/placeholder.jpg',
    description: 'Fungal disease that generally affects the lower foliage. Shows small, circular spots.'
  },
];

export default function History() {
  const navigate = useNavigate();
  const [searchTerm, setSearchTerm] = useState('');

  const filteredHistory = MOCK_HISTORY.filter(h => 
    h.disease.toLowerCase().includes(searchTerm.toLowerCase()) || 
    h.crop.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: { 
      opacity: 1, 
      transition: { staggerChildren: 0.1 } 
    }
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 15 },
    visible: { opacity: 1, y: 0 }
  };

  const handleRowClick = (item) => {
    // Navigate to /result with the exact data needed by Result.jsx
    navigate('/result', {
      state: {
        resultData: {
          diseaseName: item.disease,
          confidence: item.confidence,
          status: item.status,
          description: item.description
        },
        image: item.img
      }
    });
  };

  return (
    <div style={{ minHeight: '100vh', background: '#F4F7F6', paddingBottom: '6rem', fontFamily: '"Outfit", sans-serif' }}>

      {/* Header Container */}
      <div style={{ background: '#0F172A', color: 'white', padding: '4rem 2rem 6rem 2rem', borderBottomLeftRadius: '48px', borderBottomRightRadius: '48px', position: 'relative' }}>
        <div style={{ maxWidth: '900px', margin: '0 auto', display: 'flex', flexDirection: 'column', gap: '2rem' }}>
          <div>
            <h1 style={{ fontSize: '3rem', fontWeight: 800, margin: '0 0 0.5rem 0', letterSpacing: '-0.02em', display: 'flex', alignItems: 'center', gap: '1rem' }}>
              <Clock size={40} color="#22C55E" /> Scan History
            </h1>
            <p style={{ color: '#94A3B8', fontSize: '1.1rem', margin: 0 }}>Review past analyses, jump back into reports, and monitor crop health trends over time.</p>
          </div>

          <div style={{ display: 'flex', alignItems: 'center', background: 'rgba(255,255,255,0.1)', padding: '1rem 1.5rem', borderRadius: '20px', border: '1px solid rgba(255,255,255,0.1)', backdropFilter: 'blur(10px)', width: '100%', maxWidth: '500px' }}>
            <Search size={22} color="#94A3B8" />
            <input 
              type="text" 
              placeholder="Search by crop or disease name..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              style={{ background: 'transparent', border: 'none', outline: 'none', width: '100%', fontSize: '1.1rem', color: 'white', marginLeft: '1rem' }} 
            />
          </div>
        </div>
      </div>

      {/* Main Content Area */}
      <motion.div 
        variants={containerVariants}
        initial="hidden"
        animate="visible"
        style={{ maxWidth: '900px', margin: '-3rem auto 0 auto', padding: '0 1.5rem' }}
      >
        <div style={{ background: 'white', borderRadius: '32px', boxShadow: '0 20px 40px -10px rgba(0,0,0,0.1)', border: '1px solid rgba(0,0,0,0.02)', padding: '1rem' }}>
          <AnimatePresence>
            {filteredHistory.length > 0 ? filteredHistory.map((item, i) => {
              const isHealthy = item.status === 'Healthy';
              const statusColor = isHealthy ? '#10B981' : '#F43F5E';
              const statusBg = isHealthy ? 'rgba(16, 185, 129, 0.1)' : 'rgba(244, 63, 94, 0.1)';

              return (
                <motion.div 
                  key={item.id} 
                  variants={itemVariants}
                  layoutId={item.id}
                  onClick={() => handleRowClick(item)}
                  style={{ 
                    padding: '1.5rem', 
                    borderRadius: '24px', 
                    display: 'flex', 
                    alignItems: 'center', 
                    justifyContent: 'space-between', 
                    cursor: 'pointer', 
                    outline: '2px solid transparent',
                    background: i % 2 === 0 ? 'transparent' : '#F8FAFC',
                    transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)'
                  }} 
                  onMouseOver={e => {
                    e.currentTarget.style.background = 'rgba(241, 245, 249, 0.8)';
                    e.currentTarget.style.transform = 'scale(1.02)';
                    e.currentTarget.style.boxShadow = '0 10px 25px -5px rgba(0,0,0,0.05)';
                    e.currentTarget.style.zIndex = 10;
                  }} 
                  onMouseOut={e => {
                    e.currentTarget.style.background = i % 2 === 0 ? 'transparent' : '#F8FAFC';
                    e.currentTarget.style.transform = 'scale(1)';
                    e.currentTarget.style.boxShadow = 'none';
                    e.currentTarget.style.zIndex = 1;
                  }}
                >
                  <div style={{ display: 'flex', alignItems: 'center', gap: '1.5rem' }}>
                    <div style={{ width: '90px', height: '90px', borderRadius: '20px', overflow: 'hidden', background: '#1E293B', flexShrink: 0 }}>
                      <img 
                        src={item.img} 
                        alt={item.crop} 
                        style={{ width: '100%', height: '100%', objectFit: 'cover', opacity: 0.8 }} 
                        onError={e => e.target.style.background = 'linear-gradient(45deg, #11231c, #163628)'}
                      />
                    </div>

                    <div>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '0.5rem' }}>
                        <span style={{ background: '#F1F5F9', color: '#475569', padding: '0.25rem 0.75rem', borderRadius: '8px', fontSize: '0.75rem', fontWeight: 700, letterSpacing: '0.05em' }}>{item.id}</span>
                        <h4 style={{ fontSize: '1.4rem', fontWeight: 800, color: '#0F172A', margin: 0 }}>{item.disease}</h4>
                      </div>
                      <div style={{ display: 'flex', gap: '1.5rem', color: '#64748B', fontSize: '0.95rem', fontWeight: 500, alignItems: 'center' }}>
                        <span style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', color: '#334155' }}>
                          <span style={{ fontWeight: 600 }}>Crop:</span> {item.crop}
                        </span>
                        <span style={{ display: 'flex', alignItems: 'center', gap: '0.4rem' }}>
                          <Calendar size={16} /> {item.date}
                        </span>
                      </div>
                    </div>
                  </div>

                  <div style={{ display: 'flex', alignItems: 'center', gap: '2rem' }}>
                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: '0.5rem' }}>
                      <span style={{ 
                        background: statusBg, 
                        color: statusColor, 
                        padding: '0.4rem 1rem', 
                        borderRadius: '99px',
                        fontSize: '0.85rem',
                        fontWeight: 700,
                        display: 'flex',
                        alignItems: 'center',
                        gap: '0.4rem'
                      }}>
                        {isHealthy ? <CheckCircle size={14} strokeWidth={3} /> : <ShieldAlert size={14} strokeWidth={3} />}
                        {item.status.toUpperCase()}
                      </span>
                      <span style={{ fontSize: '0.85rem', color: '#94A3B8', fontWeight: 600 }}>Confidence: {Math.round(item.confidence * 100)}%</span>
                    </div>

                    <div style={{ background: 'white', border: '1px solid #E2E8F0', padding: '0.75rem', borderRadius: '50%', color: '#0F172A', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 4px 12px rgba(0,0,0,0.03)' }}>
                      <ChevronRight size={20} />
                    </div>
                  </div>
                </motion.div>
              );
            }) : (
              <div style={{ padding: '4rem', textAlign: 'center', color: '#64748B', fontSize: '1.1rem' }}>
                No scan history found for "{searchTerm}".
              </div>
            )}
          </AnimatePresence>
        </div>
      </motion.div>
    </div>
  );
}

import { motion } from 'framer-motion';
import { Link } from 'react-router-dom';
import { ArrowRight, Scan, Sprout, Activity, Database } from 'lucide-react';

export default function Landing() {
  return (
    <div style={{ width: '100%', fontFamily: '"Outfit", sans-serif', background: '#090D14', color: 'white', overflowX: 'hidden', position: 'relative' }}>

      {/* Premium ambient glows */}
      <div style={{ position: 'absolute', top: '-10%', left: '-10%', width: '50vw', height: '50vw', background: 'radial-gradient(circle, rgba(34,197,94,0.15) 0%, rgba(9,13,20,0) 70%)', filter: 'blur(80px)', zIndex: 0, pointerEvents: 'none' }} />
      <div style={{ position: 'absolute', top: '20%', right: '-10%', width: '40vw', height: '40vw', background: 'radial-gradient(circle, rgba(59,130,246,0.1) 0%, rgba(9,13,20,0) 70%)', filter: 'blur(80px)', zIndex: 0, pointerEvents: 'none' }} />

      {/* Hero Section */}
      <section style={{ 
        position: 'relative',
        display: 'flex', 
        flexDirection: 'column', 
        alignItems: 'center', 
        justifyContent: 'center',
        textAlign: 'center', 
        padding: '12rem 2rem 10rem 2rem',
        minHeight: '100vh',
        zIndex: 10
      }}>

        <div style={{ zIndex: 10, position: 'relative', maxWidth: '1100px', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>

          <motion.div 
            initial={{ opacity: 0, y: -20, scale: 0.9 }} 
            animate={{ opacity: 1, y: 0, scale: 1 }} 
            transition={{ duration: 0.8, ease: "easeOut" }}
          >
            <div style={{ display: 'inline-flex', alignItems: 'center', gap: '0.5rem', background: 'linear-gradient(90deg, rgba(34,197,94,0.1) 0%, rgba(16,185,129,0.05) 100%)', border: '1px solid rgba(34, 197, 94, 0.3)', borderRadius: '999px', padding: '0.5rem 1.25rem', marginBottom: '2.5rem', color: '#4ADE80', fontSize: '0.95rem', fontWeight: 600, backdropFilter: 'blur(12px)', boxShadow: '0 0 20px rgba(34, 197, 94, 0.15)' }}>
              <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: '#4ADE80', boxShadow: '0 0 10px #4ADE80' }} /> 
              AgriScan AI v2.5 is now Live <ArrowRight size={14} style={{ marginLeft: '4px' }}/>
            </div>
          </motion.div>

          <motion.h1 
            initial={{ opacity: 0, y: 30 }} 
            animate={{ opacity: 1, y: 0 }} 
            transition={{ delay: 0.2, duration: 0.9, cubicBezier: [0.16, 1, 0.3, 1] }}
            style={{ fontSize: 'clamp(3.5rem, 8vw, 6.5rem)', fontWeight: 800, lineHeight: 1.05, margin: '0 0 1.5rem 0', letterSpacing: '-0.04em' }}
          >
            Diagnose <span style={{ background: 'linear-gradient(135deg, #4ADE80 0%, #10B981 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', filter: 'drop-shadow(0px 4px 20px rgba(34,197,94,0.3))' }}>Crop Diseases</span> <br /> in Milliseconds.
          </motion.h1>

          <motion.p 
            initial={{ opacity: 0, y: 30 }} 
            animate={{ opacity: 1, y: 0 }} 
            transition={{ delay: 0.3, duration: 0.9, cubicBezier: [0.16, 1, 0.3, 1] }}
            style={{ fontSize: '1.25rem', maxWidth: '750px', margin: '0 auto 3.5rem auto', color: '#94A3B8', lineHeight: 1.7, fontWeight: 400 }}
          >
            Transform your smartphone into an elite agronomy expert. Leverage our state-of-the-art computer vision models to instantly recognize diseases, predict yield impact, and prescribe actionable treatments.
          </motion.p>

          <motion.div 
            initial={{ opacity: 0, y: 30 }} 
            animate={{ opacity: 1, y: 0 }} 
            transition={{ delay: 0.4, duration: 0.9, cubicBezier: [0.16, 1, 0.3, 1] }} 
            style={{ display: 'flex', gap: '1.25rem', flexWrap: 'wrap', justifyContent: 'center' }}
          >
            <Link to="/upload" style={{ position: 'relative', display: 'flex', alignItems: 'center', gap: '0.75rem', background: '#22C55E', color: 'white', padding: '1.25rem 2.5rem', borderRadius: '16px', fontSize: '1.1rem', fontWeight: 600, textDecoration: 'none', transition: 'all 0.3s cubic-bezier(0.16, 1, 0.3, 1)', boxShadow: '0 20px 40px -10px rgba(34, 197, 94, 0.5)', overflow: 'hidden' }} onMouseOver={e => {e.currentTarget.style.transform = 'translateY(-4px)'; e.currentTarget.style.boxShadow = '0 25px 50px -10px rgba(34, 197, 94, 0.6)';}} onMouseOut={e => {e.currentTarget.style.transform = 'translateY(0)'; e.currentTarget.style.boxShadow = '0 20px 40px -10px rgba(34, 197, 94, 0.5)';}}>
               <Scan size={22} /> Start Diagnostic Scan
            </Link>
            <Link to="/register" style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', background: 'rgba(255,255,255,0.03)', color: 'white', border: '1px solid rgba(255,255,255,0.1)', padding: '1.25rem 2.5rem', borderRadius: '16px', fontSize: '1.1rem', fontWeight: 600, textDecoration: 'none', transition: 'all 0.3s cubic-bezier(0.16, 1, 0.3, 1)', backdropFilter: 'blur(20px)', boxShadow: '0 4px 20px rgba(0,0,0,0.1)' }} onMouseOver={e => {e.currentTarget.style.background = 'rgba(255,255,255,0.08)'; e.currentTarget.style.borderColor = 'rgba(255,255,255,0.2)';}} onMouseOut={e => {e.currentTarget.style.background = 'rgba(255,255,255,0.03)'; e.currentTarget.style.borderColor = 'rgba(255,255,255,0.1)';}}>
              Create Free Account <ArrowRight size={18} />
            </Link>
          </motion.div>
        </div>

        {/* Floating Mockup/Visual */}
        <motion.div 
          initial={{ opacity: 0, y: 100 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.6, duration: 1.2, type: 'spring', damping: 25 }}
          style={{ width: '100%', maxWidth: '1000px', height: '400px', marginTop: '6rem', position: 'relative', borderRadius: '32px', background: 'linear-gradient(180deg, rgba(30,41,59,0.8) 0%, rgba(15,23,42,0) 100%)', border: '1px solid rgba(255,255,255,0.05)', borderBottom: 'none', backdropFilter: 'blur(20px)', overflow: 'hidden' }}
        >
          {/* Abstract Interface Elements */}
          <div style={{ position: 'absolute', top: '2rem', left: '50%', transform: 'translateX(-50%)', width: '80%', height: '80%', background: 'rgba(15,23,42,0.6)', borderRadius: '24px', border: '1px solid rgba(255,255,255,0.05)', padding: '2rem', display: 'flex', gap: '2rem' }}>
             <div style={{ flex: 1, borderRadius: '16px', background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(255,255,255,0.05)', padding: '1.5rem', display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                <div style={{ width: '40%', height: '1.5rem', background: 'rgba(255,255,255,0.05)', borderRadius: '8px' }} />
                <div style={{ width: '100%', height: '10rem', background: 'rgba(34,197,94,0.1)', borderRadius: '12px', border: '1px dashed rgba(34,197,94,0.3)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                  <Scan color="#4ADE80" size={40} />
                </div>
             </div>
             <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                <div style={{ width: '100%', height: '4rem', background: 'rgba(255,255,255,0.03)', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.05)' }} />
                <div style={{ width: '100%', height: '4rem', background: 'rgba(255,255,255,0.03)', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.05)' }} />
                <div style={{ width: '100%', height: '4rem', background: 'rgba(255,255,255,0.03)', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.05)' }} />
             </div>
          </div>
          {/* Gradient Overlay for Fade out */}
          <div style={{ position: 'absolute', bottom: 0, left: 0, right: 0, height: '50%', background: 'linear-gradient(to bottom, transparent, #090D14)' }} />
        </motion.div>
      </section>

      {/* Features Grid */}
      <section style={{ maxWidth: '1280px', margin: '4rem auto 10rem auto', padding: '0 2rem', position: 'relative', zIndex: 10 }}>

        <div style={{ textAlign: 'center', marginBottom: '5rem' }}>
          <h2 style={{ fontSize: '3rem', fontWeight: 800, color: 'white', letterSpacing: '-0.02em', marginBottom: '1rem' }}>Engineered for <span style={{ color: '#4ADE80' }}>Precision</span></h2>
          <p style={{ color: '#94A3B8', fontSize: '1.2rem', maxWidth: '600px', margin: '0 auto' }}>A comprehensive suite of tools designed to protect your yield and maximize harvest potential.</p>
        </div>

        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))', gap: '2rem' }}>

          <motion.div 
            initial={{ opacity: 0, y: 30 }} whileInView={{ opacity: 1, y: 0 }} viewport={{ once: true, margin: "-100px" }} transition={{ duration: 0.7 }} 
            className="feature-card"
            style={{ background: 'linear-gradient(145deg, rgba(30,41,59,0.4) 0%, rgba(15,23,42,0.4) 100%)', border: '1px solid rgba(255,255,255,0.05)', padding: '3.5rem 2.5rem', borderRadius: '32px', transition: 'all 0.3s ease', backdropFilter: 'blur(20px)', boxShadow: '0 20px 40px rgba(0,0,0,0.2)' }}
            onMouseOver={e => e.currentTarget.style.borderColor = 'rgba(59,130,246,0.3)'}
