import React, { useState, useRef } from 'react';
import { Camera, ChevronLeft, ArrowRight, Zap, Image as ImageIcon } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import axios from 'axios';

export default function UploadScan() {
  const [file, setFile] = useState(null);
  const [loading, setLoading] = useState(false);
  const [dragActive, setDragActive] = useState(false);
  const fileInputRef = useRef(null);
  const cameraInputRef = useRef(null);
  const navigate = useNavigate();

  const handleDrag = (e) => { 
    e.preventDefault(); e.stopPropagation(); 
    if (e.type === "dragenter" || e.type === "dragover") setDragActive(true); 
    else if (e.type === "dragleave") setDragActive(false); 
  };

  const handleDrop = (e) => { 
    e.preventDefault(); e.stopPropagation(); 
    setDragActive(false); 
    if (e.dataTransfer.files && e.dataTransfer.files[0]) setFile(e.dataTransfer.files[0]); 
  };

  const handleChange = (e) => { 
    e.preventDefault(); 
    if (e.target.files && e.target.files[0]) setFile(e.target.files[0]); 
  };

  const handleAnalyze = async () => {
    if (!file) return;
    setLoading(true);
    const formData = new FormData();
    formData.append('image', file);
    try {
      const response = await axios.post('http://localhost:5000/api/predict', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      setTimeout(() => {
        setLoading(false);
        navigate('/result', { state: { resultData: response.data, image: URL.createObjectURL(file) } });
      }, 1500);
    } catch (error) {
      console.error("Analysis failed", error);
      setTimeout(() => {
        setLoading(false);
        navigate('/result', { state: { image: URL.createObjectURL(file) } });
      }, 1500);
    }
  };

  return (
    <div style={{ backgroundColor: '#F8FAFC', minHeight: '100vh', width: '100%' }}>
      <motion.div 
        initial={{ opacity: 0, y: 20 }} 
        animate={{ opacity: 1, y: 0 }} 
        transition={{ duration: 0.6, ease: [0.16, 1, 0.3, 1] }}
        style={{ maxWidth: '640px', margin: '0 auto', paddingTop: '3rem', paddingBottom: '6rem', paddingLeft: '1.5rem', paddingRight: '1.5rem', display: 'flex', flexDirection: 'column', alignItems: 'center', fontFamily: '"Outfit", sans-serif' }}
      >
        {/* Header */}
        <div style={{ display: 'flex', alignItems: 'center', width: '100%', marginBottom: '3rem' }}>
          <button onClick={() => navigate(-1)} style={{ background: 'white', border: '1px solid rgba(0,0,0,0.05)', borderRadius: '16px', width: '48px', height: '48px', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', boxShadow: '0 10px 20px -5px rgba(0,0,0,0.05)', transition: 'all 0.3s' }} onMouseOver={e=>e.currentTarget.style.transform='translateY(-2px)'} onMouseOut={e=>e.currentTarget.style.transform='translateY(0)'}>
            <ChevronLeft size={24} color="#0F172A" />
          </button>
          <div style={{ flex: 1, textAlign: 'center', paddingRight: '48px' }}>
            <h2 style={{ fontSize: '1.5rem', fontWeight: 800, color: '#0F172A', margin: 0, letterSpacing: '-0.02em' }}>Diagnostic Scan</h2>
            <p style={{ margin: 0, color: '#64748B', fontSize: '0.9rem', fontWeight: 500 }}>Upload a photo for AI analysis</p>
          </div>
        </div>

        {/* Main Scan Box */}
        <div 
          style={{
            width: '100%',
            aspectRatio: '3/4',
            background: file ? '#000' : 'white',
            border: file ? 'none' : `2px dashed ${dragActive ? '#22C55E' : 'rgba(0,0,0,0.1)'}`,
            borderRadius: '40px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            position: 'relative',
            overflow: 'hidden',
            marginBottom: '2rem',
            boxShadow: file ? '0 30px 60px -15px rgba(0,0,0,0.3)' : '0 20px 40px -15px rgba(0,0,0,0.05)',
            transition: 'all 0.4s cubic-bezier(0.16, 1, 0.3, 1)'
          }}
          onDragEnter={handleDrag} onDragLeave={handleDrag} onDragOver={handleDrag} onDrop={handleDrop}
        >
          {/* Futuristic Focus Brackets */}
          <div style={{ position: 'absolute', top: '10%', left: '10%', right: '10%', bottom: '10%', pointerEvents: 'none', transition: 'all 0.4s', opacity: file ? 1 : 0.2 }}>
            <div style={{ position: 'absolute', top: 0, left: 0, width: '40px', height: '40px', borderTop: '4px solid #22C55E', borderLeft: '4px solid #22C55E', borderRadius: '16px 0 0 0', zIndex: 10, filter: 'drop-shadow(0 0 8px rgba(34,197,94,0.5))' }}></div>
            <div style={{ position: 'absolute', top: 0, right: 0, width: '40px', height: '40px', borderTop: '4px solid #22C55E', borderRight: '4px solid #22C55E', borderRadius: '0 16px 0 0', zIndex: 10, filter: 'drop-shadow(0 0 8px rgba(34,197,94,0.5))' }}></div>
            <div style={{ position: 'absolute', bottom: 0, left: 0, width: '40px', height: '40px', borderBottom: '4px solid #22C55E', borderLeft: '4px solid #22C55E', borderRadius: '0 0 0 16px', zIndex: 10, filter: 'drop-shadow(0 0 8px rgba(34,197,94,0.5))' }}></div>
            <div style={{ position: 'absolute', bottom: 0, right: 0, width: '40px', height: '40px', borderBottom: '4px solid #22C55E', borderRight: '4px solid #22C55E', borderRadius: '0 0 16px 0', zIndex: 10, filter: 'drop-shadow(0 0 8px rgba(34,197,94,0.5))' }}></div>
          </div>

          {!file ? (
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', textAlign: 'center', padding: '2rem', zIndex: 5 }}>
              <div 
                style={{ width: '90px', height: '90px', background: 'linear-gradient(135deg, rgba(34,197,94,0.1) 0%, rgba(16,185,129,0.05) 100%)', border: '1px solid rgba(34,197,94,0.2)', borderRadius: '28px', display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: '2rem', boxShadow: '0 15px 30px -10px rgba(34,197,94,0.15)', cursor: 'pointer', transition: 'all 0.3s' }}
                onClick={() => fileInputRef.current?.click()}
                onMouseOver={e=>e.currentTarget.style.transform='scale(1.05)'} onMouseOut={e=>e.currentTarget.style.transform='scale(1)'}
              >
                <ImageIcon size={40} color="#22C55E" strokeWidth={1.5} />
              </div>
              <h3 style={{ fontSize: '1.4rem', fontWeight: 800, color: '#0F172A', cursor: 'pointer', marginBottom: '0.75rem', letterSpacing: '-0.02em' }} onClick={() => fileInputRef.current?.click()}>
                Upload Plant Photo
              </h3>
              <p style={{ color: '#64748B', fontSize: '1.05rem', fontWeight: 400, maxWidth: '220px', lineHeight: 1.5 }}>Drag & drop an image or tap icon to select from gallery</p>
            </div>
          ) : (
            <>
              <motion.img initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: loading ? 0.5 : 1, scale: 1 }} transition={{ duration: 0.5 }} src={URL.createObjectURL(file)} alt="Preview" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />

              {/* Animated Scanning Line */}
              {loading && (
                <motion.div 
                  animate={{ top: ['0%', '100%', '0%'] }}
                  transition={{ duration: 3, repeat: Infinity, ease: 'linear' }}
                  style={{ position: 'absolute', left: 0, right: 0, height: '6px', background: 'linear-gradient(90deg, transparent 0%, #4ADE80 50%, transparent 100%)', boxShadow: '0 0 40px 10px rgba(74,222,128,0.5)', zIndex: 20 }}
                />
              )}

              <AnimatePresence>
                {loading && (
                   <motion.div 
                     initial={{ opacity: 0, y: 20 }}
                     animate={{ opacity: 1, y: 0 }}
                     exit={{ opacity: 0, y: 20 }}
                     style={{ position: 'absolute', background: 'rgba(15,23,42,0.85)', backdropFilter: 'blur(16px)', padding: '1.25rem 2.5rem', borderRadius: '99px', display: 'flex', alignItems: 'center', gap: '0.75rem', zIndex: 30, border: '1px solid rgba(255,255,255,0.1)', color: 'white', fontWeight: 600, boxShadow: '0 20px 40px rgba(0,0,0,0.5)' }}
                   >
                      <Zap size={20} className="pulse-fast" color="#4ADE80" fill="#4ADE80" /> Analyzing AI Vision...
                   </motion.div>
                )}
              </AnimatePresence>
            </>
          )}
        </div>

        <input ref={fileInputRef} type="file" accept="image/jpeg, image/png, image/webp" onChange={handleChange} style={{ display: 'none' }} />
        {/* capture="environment" strictly triggers the mobile rear camera for "Take a Photo" feature */}
        <input ref={cameraInputRef} type="file" accept="image/jpeg, image/png, image/webp" capture="environment" onChange={handleChange} style={{ display: 'none' }} />

        {!file ? (
          <button 
            onClick={() => cameraInputRef.current?.click()}
            style={{ width: '100%', background: '#0F172A', color: 'white', padding: '1.5rem', borderRadius: '24px', fontSize: '1.15rem', fontWeight: 700, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.75rem', border: 'none', cursor: 'pointer', boxShadow: '0 20px 40px -10px rgba(15, 23, 42, 0.4)', transition: 'all 0.3s cubic-bezier(0.16, 1, 0.3, 1)' }}
            onMouseOver={e=>{e.currentTarget.style.transform='translateY(-4px)'; e.currentTarget.style.boxShadow='0 25px 50px -15px rgba(15,23,42,0.5)';}} onMouseOut={e=>{e.currentTarget.style.transform='translateY(0)'; e.currentTarget.style.boxShadow='0 20px 40px -10px rgba(15,23,42,0.4)';}}
          >
            <Camera size={26} /> Open Device Camera
          </button>
        ) : (
          <div style={{ display: 'flex', gap: '1rem', width: '100%' }}>
            <button 
              onClick={() => setFile(null)} 
              disabled={loading}
              style={{ flex: 1, background: 'white', color: '#0F172A', padding: '1.5rem', border: '1px solid rgba(0,0,0,0.1)', borderRadius: '24px', fontSize: '1.1rem', fontWeight: 700, cursor: loading ? 'not-allowed' : 'pointer', transition: 'all 0.3s', opacity: loading ? 0.5 : 1, boxShadow: '0 10px 20px -5px rgba(0,0,0,0.05)' }}
            >
              Cancel
            </button>
            <button 
              onClick={handleAnalyze} 
              disabled={loading} 
              style={{ flex: 2, background: 'linear-gradient(135deg, #22C55E 0%, #16A34A 100%)', color: 'white', padding: '1.5rem', border: 'none', borderRadius: '24px', fontSize: '1.15rem', fontWeight: 700, cursor: loading ? 'not-allowed' : 'pointer', transition: 'all 0.3s cubic-bezier(0.16, 1, 0.3, 1)', boxShadow: loading ? 'none' : '0 20px 40px -10px rgba(34, 197, 94, 0.5)', opacity: loading ? 0.8 : 1, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.75rem' }}
              onMouseOver={e=>!loading && (e.currentTarget.style.transform='translateY(-4px)')} onMouseOut={e=>!loading && (e.currentTarget.style.transform='translateY(0)')}
            >
              {loading ? 'Processing...' : <>Run Diagnosis <ArrowRight size={22} /></>}
            </button>
          </div>
        )}
        <style>{`
          .pulse-fast {
            animation: pulse-op 1s ease-in-out infinite alternate;
          }
